import{_ as p,c as t}from"./app.0b00aae6.js";const r={},o=t('<h1 id="_02-\u8BB2-\u5982\u4F55\u8BBE\u8BA1\u4E00\u4E2A-\u597D\u7684-\u6D4B\u8BD5\u7528\u4F8B" tabindex="-1"><a class="header-anchor" href="#_02-\u8BB2-\u5982\u4F55\u8BBE\u8BA1\u4E00\u4E2A-\u597D\u7684-\u6D4B\u8BD5\u7528\u4F8B" aria-hidden="true">#</a> 02 \u8BB2\uFF1A\u5982\u4F55\u8BBE\u8BA1\u4E00\u4E2A\u201C\u597D\u7684\u201D\u6D4B\u8BD5\u7528\u4F8B\uFF1F</h1><p>\u5728\u4E0A\u4E00\u7BC7\u6587\u7AE0\u4E2D\uFF0C\u6211\u4EE5\u201C\u7528\u6237\u767B\u5F55\u201D\u8FD9\u4E00\u7B80\u5355\u76F4\u63A5\u7684\u529F\u80FD\u4F5C\u4E3A\u6D4B\u8BD5\u5BF9\u8C61\uFF0C\u4E3A\u4F60\u4ECB\u7ECD\u4E86\u5982\u4F55\u8BBE\u8BA1\u6D4B\u8BD5\u7528\u4F8B\u3002\u73B0\u5728\u4F60\u5E94\u8BE5\u5DF2\u7ECF\u77E5\u9053\uFF0C\u4E3A\u4E86\u4FDD\u8BC1\u8F6F\u4EF6\u7CFB\u7EDF\u7684\u8D28\u91CF\uFF0C\u6D4B\u8BD5\u7528\u4F8B\u7684\u8BBE\u8BA1\u4E0D\u4EC5\u9700\u8981\u8003\u8651\u529F\u80FD\u6027\u9700\u6C42\uFF0C\u8FD8\u8981\u8003\u8651\u5927\u91CF\u7684\u975E\u529F\u80FD\u6027\u9700\u6C42\u3002</p><p>\u90A3\u4E48\uFF0C\u4ECA\u5929\u6211\u4F1A\u91CD\u70B9\u548C\u4F60\u63A2\u8BA8\u5982\u4F55\u624D\u80FD\u8BBE\u8BA1\u51FA\u4E00\u4E2A\u201C\u597D\u7684\u201D\u6D4B\u8BD5\u7528\u4F8B\u3002</p><p><strong>\u4EC0\u4E48\u624D\u7B97\u662F\u201C\u597D\u7684\u201D\u6D4B\u8BD5\u7528\u4F8B\uFF1F</strong></p><p>\u5728\u6B63\u5F0F\u5F00\u59CB\u8BA8\u8BBA\u4E4B\u524D\uFF0C\u6211\u5148\u8DDF\u4F60\u804A\u804A\uFF0C\u4EC0\u4E48\u624D\u662F\u201C\u597D\u7684\u201D\u6D4B\u8BD5\u7528\u4F8B\uFF0C\u8FD9\u4E2A\u201C\u597D\u201D\u53C8\u5E94\u8BE5\u4F53\u73B0\u5728\u54EA\u4E9B\u65B9\u9762\u3002\u8FD9\u662F\u4E00\u4E2A\u770B\u4F3C\u7B80\u5355\u5B9E\u5219\u96BE\u4EE5\u56DE\u7B54\u7684\u95EE\u9898\uFF0C\u5373\u4F7F\u6DF1\u5165\u601D\u8003\u540E\uFF0C\u4E5F\u5F88\u96BE\u6709\u975E\u5E38\u6807\u51C6\u7684\u7B54\u6848\u3002</p><p>\u901A\u5E38\uFF0C\u4F60\u7684\u7B2C\u4E00\u53CD\u5E94\u5F88\u53EF\u80FD\u4F1A\u662F\u201C\u53D1\u73B0\u4E86\u8F6F\u4EF6\u7F3A\u9677\u7684\u6D4B\u8BD5\u7528\u4F8B\u5C31\u662F\u597D\u7684\u7528\u4F8B\u201D\uFF0C\u6211\u53EF\u80FD\u4F1A\u53CD\u95EE\u4F60\u201C\u5982\u679C\u8BF4\u6D4B\u8BD5\u7528\u4F8B\u53D1\u73B0\u4E86\u7F3A\u9677\u5C31\u662F\u597D\u7528\u4F8B\uFF0C\u90A3\u4E48\u5728\u8BE5\u7F3A\u9677\u88AB\u4FEE\u590D\u540E\uFF0C\u540C\u6837\u7684\u7528\u4F8B\u96BE\u9053\u5C31\u4E0D\u662F\u597D\u7528\u4F8B\u4E86\u5417\uFF1F\u201D\u3002</p><p>\u4F60\u53EF\u80FD\u8FD8\u4F1A\u8BF4\u201C\u53D1\u73B0\u8F6F\u4EF6\u7F3A\u9677\u53EF\u80FD\u6027\u5927\u7684\u6D4B\u8BD5\u7528\u4F8B\u5C31\u662F\u597D\u7528\u4F8B\u201D\uFF0C\u8FD9\u8BDD\u770B\u8D77\u6765\u8FD8\u662F\u86EE\u6709\u9053\u7406\u7684\uFF0C\u4F46\u662F\u6211\u540C\u6837\u4F1A\u53CD\u95EE\u4F60\u201C\u4F60\u6253\u7B97\u7528\u4EC0\u4E48\u65B9\u6CD5\u6765\u91CF\u5316\u6D4B\u8BD5\u7528\u4F8B\u53D1\u73B0\u7F3A\u9677\u7684\u53EF\u80FD\u6027\uFF1F\u201D\u3002</p><p>\u7C7B\u4F3C\u5730\uFF0C\u4F60\u53EF\u80FD\u8FD8\u4F1A\u8BF4\u201C\u53D1\u73B0\u81F3\u4ECA\u672A\u88AB\u53D1\u73B0\u7684\u8F6F\u4EF6\u7F3A\u9677\u7684\u6D4B\u8BD5\u7528\u4F8B\u5C31\u662F\u597D\u7528\u4F8B\u201D\uFF0C\u90A3\u4E48\u6211\u60F3\u95EE\u4F60\u7684\u662F\uFF1A\u5982\u4F55\u8BC4\u4F30\u662F\u5426\u8FD8\u5B58\u5728\u672A\u88AB\u53D1\u73B0\u7684\u7F3A\u9677\uFF1F\u5982\u679C\u8F6F\u4EF6\u4E2D\u6839\u672C\u5C31\u6CA1\u6709\u9519\u8BEF\u4E86\u5462\uFF1F</p><p>\u5176\u5B9E\uFF0C\u662F\u4F60\u5B9A\u4E49\u201C\u597D\u7684\u201D\u6D4B\u8BD5\u7528\u4F8B\u7684\u601D\u8DEF\u9519\u4E86\uFF0C\u8FD9\u5C31\u6709\u70B9\u50CF\u201C\u50BB\u5B50\u5403\u70E7\u997C\u201D\uFF0C\u8FDE\u5403\u4E94\u4E2A\u4E0D\u9971\uFF0C\u5403\u5B8C\u7B2C\u516D\u4E2A\u7EC8\u4E8E\u9971\u4E86\uFF0C\u4E8E\u662F\u4ED6\u8BF4\uFF1A\u65E9\u77E5\u9053\u5403\u4E86\u7B2C\u516D\u4E2A\u5C31\u4F1A\u9971\uFF0C\u4F55\u5FC5\u5403\u524D\u9762\u4E94\u4E2A\u5462\u3002\u7EC6\u60F3\uFF0C\u4ED6\u5403\u7684\u516D\u4E2A\u70E7\u997C\u5176\u5B9E\u662F\u4E00\u4E2A\u6574\u4F53\uFF0C\u4E00\u8D77\u5403\u4E0B\u53BB\u624D\u4F1A\u9971\uFF0C\u800C\u4F60\u65E0\u6CD5\u627E\u5230\u5403\u4E00\u4E2A\u5C31\u80FD\u9971\u7684\u201C\u597D\u201D\u70E7\u997C\u3002</p><p>\u5BF9\u4E8E\u6D4B\u8BD5\u7528\u4F8B\u5176\u5B9E\u4E5F\u662F\u540C\u6837\u7684\u9053\u7406\uFF0C<strong>\u201C\u597D\u7684\u201D\u6D4B\u8BD5\u7528\u4F8B\u4E00\u5B9A\u662F\u4E00\u4E2A\u5B8C\u5907\u7684\u96C6\u5408\uFF0C\u5B83\u80FD\u591F\u8986\u76D6\u6240\u6709\u7B49\u4EF7\u7C7B\u4EE5\u53CA\u5404\u79CD\u8FB9\u754C\u503C\uFF0C\u800C\u8DDF\u80FD\u5426\u53D1\u73B0\u7F3A\u9677\u65E0\u5173</strong>\u3002</p><p>\u6211\u4E3E\u4E00\u4E2A\u201C\u6C60\u5858\u6355\u9C7C\u201D\u7684\u4F8B\u5B50\uFF0C\u53EF\u4EE5\u5E2E\u4F60\u66F4\u597D\u5730\u7406\u89E3\u4EC0\u4E48\u662F\u201C\u597D\u7684\u201D\u6D4B\u8BD5\u7528\u4F8B\u3002</p><p>\u5982\u679C\u628A\u88AB\u6D4B\u8BD5\u8F6F\u4EF6\u770B\u4F5C\u4E00\u4E2A\u6C60\u5858\uFF0C\u8F6F\u4EF6\u7F3A\u9677\u662F\u6C60\u5858\u4E2D\u7684\u9C7C\uFF0C\u5EFA\u7ACB\u6D4B\u8BD5\u7528\u4F8B\u96C6\u7684\u8FC7\u7A0B\u5C31\u50CF\u662F\u5728\u7F16\u7EC7\u4E00\u5F20\u6355\u6E14\u7F51\u3002\u201C\u597D\u7684\u201D\u6D4B\u8BD5\u7528\u4F8B\u96C6\u5C31\u662F\u4E00\u5F20\u80FD\u591F\u8986\u76D6\u6574\u4E2A\u6C60\u5858\u7684\u5927\u6E14\u7F51\uFF0C\u53EA\u8981\u6C60\u5858\u91CC\u6709\u9C7C\uFF0C\u8FD9\u4E2A\u5927\u6E14\u7F51\u5C31\u4E00\u5B9A\u80FD\u628A\u9C7C\u7ED9\u635E\u4E0A\u6765\u3002</p><p>\u5982\u679C\u6E14\u7F51\u672C\u8EAB\u662F\u5B8C\u6574\u7684\u4E14\u5408\u683C\u7684\uFF0C\u90A3\u4E48\u635E\u4E0D\u5230\u9C7C\uFF0C\u5C31\u8BC1\u660E\u6C60\u5858\u4E2D\u6CA1\u6709\u9C7C\uFF0C\u800C\u6E14\u7F51\u7684\u597D\u574F\u4E0E\u6C60\u5858\u4E2D\u662F\u5426\u6709\u9C7C\u65E0\u5173\u3002</p><p><strong>\u201C\u597D\u7684\u201D\u6D4B\u8BD5\u7528\u4F8B\u5FC5\u987B\u5177\u5907\u54EA\u4E9B\u7279\u5F81\uFF1F</strong></p><p>\u4E00\u4E2A\u201C\u597D\u7684\u201D\u6D4B\u8BD5\u7528\u4F8B\uFF0C\u5FC5\u987B\u5177\u5907\u4EE5\u4E0B\u4E09\u4E2A\u7279\u5F81\u3002</p><ol><li><p><strong>\u6574\u4F53\u5B8C\u5907\u6027</strong>\uFF1A \u201C\u597D\u7684\u201D\u6D4B\u8BD5\u7528\u4F8B\u4E00\u5B9A\u662F\u4E00\u4E2A\u5B8C\u5907\u7684\u6574\u4F53\uFF0C\u662F\u6709\u6548\u6D4B\u8BD5\u7528\u4F8B\u7EC4\u6210\u7684\u96C6\u5408\uFF0C\u80FD\u591F\u5B8C\u5168\u8986\u76D6\u6D4B\u8BD5\u9700\u6C42\u3002</p></li><li><p><strong>\u7B49\u4EF7\u7C7B\u5212\u5206\u7684\u51C6\u786E\u6027</strong>\uFF1A \u6307\u7684\u662F\u5BF9\u4E8E\u6BCF\u4E2A\u7B49\u4EF7\u7C7B\u90FD\u80FD\u4FDD\u8BC1\u53EA\u8981\u5176\u4E2D\u4E00\u4E2A\u8F93\u5165\u6D4B\u8BD5\u901A\u8FC7\uFF0C\u5176\u4ED6\u8F93\u5165\u4E5F\u4E00\u5B9A\u6D4B\u8BD5\u901A\u8FC7\u3002</p></li><li><p><strong>\u7B49\u4EF7\u7C7B\u96C6\u5408\u7684\u5B8C\u5907\u6027</strong>\uFF1A \u9700\u8981\u4FDD\u8BC1\u6240\u6709\u53EF\u80FD\u7684\u8FB9\u754C\u503C\u548C\u8FB9\u754C\u6761\u4EF6\u90FD\u5DF2\u7ECF\u6B63\u786E\u8BC6\u522B\u3002</p></li></ol><p>\u505A\u5230\u4E86\u4EE5\u4E0A\u4E09\u70B9\uFF0C\u5C31\u53EF\u4EE5\u80AF\u5B9A\u6D4B\u8BD5\u662F\u5145\u5206\u4E14\u5B8C\u5907\u7684\uFF0C\u5373\u505A\u5230\u4E86\u5B8C\u6574\u7684\u6D4B\u8BD5\u9700\u6C42\u8986\u76D6\u3002</p><p><strong>\u4E09\u79CD\u6700\u5E38\u7528\u7684\u6D4B\u8BD5\u7528\u4F8B\u8BBE\u8BA1\u65B9\u6CD5</strong></p><p>\u660E\u767D\u4E86\u201C\u597D\u7684\u201D\u6D4B\u8BD5\u7528\u4F8B\u7684\u5185\u6DB5\u548C\u5916\u5EF6\u540E\uFF0C\u6211\u518D\u56DE\u8FC7\u5934\u6765\u7ED9\u4F60\u8BB2\u8BB2\uFF0C\u4E3A\u4E86\u80FD\u591F\u8BBE\u8BA1\u51FA\u201C\u597D\u7684\u201D\u6D4B\u8BD5\u7528\u4F8B\uFF0C\u4F60\u901A\u5E38\u90FD\u8981\u4F7F\u7528\u54EA\u4E9B\u8BBE\u8BA1\u65B9\u6CD5\u3002</p><p>\u4ECE\u7406\u8BBA\u5C42\u9762\u6765\u8BB2\uFF0C\u8BBE\u8BA1\u7528\u4F8B\u7684\u65B9\u6CD5\u6709\u5F88\u591A\uFF0C\u5982\u679C\u4F60\u53BB\u7FFB\u9605\u6D4B\u8BD5\u56FE\u4E66\u6216\u7F51\u7EDC\u6559\u7A0B\uFF0C\u4F1A\u53D1\u73B0\u4E00\u5806\u8BA9\u4EBA\u773C\u82B1\u7F2D\u4E71\u7684\u6D4B\u8BD5\u65B9\u6CD5\uFF0C\u6BD4\u5982\u7B49\u4EF7\u7C7B\u5212\u5206\u6CD5\u3001\u8FB9\u754C\u503C\u5206\u6790\u6CD5\u3001\u9519\u8BEF\u63A8\u6D4B\u65B9\u6CD5\u3001\u56E0\u679C\u56FE\u65B9\u6CD5\u3001\u5224\u5B9A\u8868\u9A71\u52A8\u5206\u6790\u6CD5\u3001\u6B63\u4EA4\u5B9E\u9A8C\u8BBE\u8BA1\u65B9\u6CD5\u3001\u529F\u80FD\u56FE\u5206\u6790\u65B9\u6CD5\u3001\u573A\u666F\u8BBE\u8BA1\u65B9\u6CD5\u3001\u5F62\u5F0F\u5316\u65B9\u6CD5\u3001\u6269\u5C55\u6709\u9650\u72B6\u6001\u673A\u65B9\u6CD5\u7B49\u7B49\uFF0C\u4F46\u662F\u4ECE\u8F6F\u4EF6\u4F01\u4E1A\u5B9E\u9645\u7684\u5DE5\u7A0B\u5B9E\u8DF5\u6765\u8BB2\uFF0C\u771F\u6B63\u5177\u6709\u5B9E\u7528\u4EF7\u503C\u5E76\u4E14\u5E38\u7528\u7684\u53EA\u6709\u524D\u4E09\u79CD\u65B9\u6CD5\u3002</p><p>\u5F53\u7136\uFF0C\u5BF9\u4E8E\u90A3\u4E9B\u4E0E\u4EBA\u7684\u751F\u547D\u5B89\u5168\u76F4\u63A5\u6216\u95F4\u63A5\u76F8\u5173\u7684\u8F6F\u4EF6\uFF0C\u6BD4\u5982\u98DE\u884C\u63A7\u5236\u3001\u8F68\u9053\u4EA4\u901A\u7684\u5217\u8F66\u63A7\u5236\u3001\u533B\u7597\u68C0\u6D4B\u76F8\u5173\u7684\u8F6F\u4EF6\u6216\u8005\u7CFB\u7EDF\uFF0C\u7531\u4E8E\u9700\u8981\u8FBE\u5230\u51E0\u8FD1\u53D8\u6001\u7684\u6D4B\u8BD5\u8986\u76D6\u7387\u8981\u6C42\uFF0C\u4F1A\u91C7\u7528\u66F4\u591A\u7684\u6D4B\u8BD5\u8BBE\u8BA1\u65B9\u6CD5\u3002\u4F46\u5BF9\u5927\u591A\u6570\u7684\u8F6F\u4EF6\u6D4B\u8BD5\u800C\u8A00\uFF0C\u7EFC\u5408\u4F7F\u7528\u7B49\u4EF7\u7C7B\u5212\u5206\u3001\u8FB9\u754C\u503C\u5206\u6790\u548C\u9519\u8BEF\u63A8\u6D4B\u8FD9\u4E09\u5927\u7C7B\u65B9\u6CD5\u5C31\u8DB3\u591F\u4E86\u3002</p><p>\u63A5\u4E0B\u6765\uFF0C\u6211\u4F1A\u7ED3\u5408\u5B9E\u9645\u7684\u4F8B\u5B50\uFF0C\u7ED9\u4F60\u89E3\u91CA\u4E00\u4E0B\u8FD9\u4E09\u7C7B\u65B9\u6CD5\u7684\u6838\u5FC3\u6982\u5FF5\u4EE5\u53CA\u5728\u4F7F\u7528\u65F6\u9700\u8981\u6CE8\u610F\u7684\u95EE\u9898\u3002</p><p><strong>\u7B2C\u4E00\uFF0C\u7B49\u4EF7\u7C7B\u5212\u5206\u65B9\u6CD5</strong></p><p>\u4ECE\u4E0A\u4E00\u7BC7\u6587\u7AE0\u4E2D\u4F60\u5DF2\u7ECF\u77E5\u9053\u4E86\uFF0C\u7B49\u4EF7\u7C7B\u4E2D\u4EFB\u610F\u4E00\u4E2A\u8F93\u5165\u6570\u636E\u5BF9\u4E8E\u63ED\u9732\u7A0B\u5E8F\u4E2D\u6F5C\u5728\u9519\u8BEF\u90FD\u5177\u6709\u540C\u7B49\u6548\u679C\u3002\u540E\u7EED<strong>\u6211\u4EEC\u53EA\u8981\u4ECE\u6BCF\u4E2A\u7B49\u4EF7\u7C7B\u4E2D\u4EFB\u610F\u9009\u53D6\u4E00\u4E2A\u503C\u8FDB\u884C\u6D4B\u8BD5\uFF0C\u5C31\u53EF\u4EE5\u7528\u5C11\u91CF\u5177\u6709\u4EE3\u8868\u6027\u7684\u6D4B\u8BD5\u8F93\u5165\u53D6\u5F97\u8F83\u597D\u7684\u6D4B\u8BD5\u8986\u76D6\u7ED3\u679C</strong>\u3002</p><p>\u73B0\u5728\uFF0C\u6211\u7ED9\u4F60\u770B\u4E00\u4E2A\u5177\u4F53\u7684\u4F8B\u5B50\uFF1A\u5B66\u751F\u4FE1\u606F\u7CFB\u7EDF\u4E2D\u6709\u4E00\u4E2A\u201C\u8003\u8BD5\u6210\u7EE9\u201D\u7684\u8F93\u5165\u9879\uFF0C\u6210\u7EE9\u7684\u53D6\u503C\u8303\u56F4\u662F 0~100 \u4E4B\u95F4\u7684\u6574\u6570\uFF0C\u8003\u8BD5\u6210\u7EE9\u53CA\u683C\u7684\u5206\u6570\u7EBF\u662F 60\u3002</p><p>\u4E3A\u4E86\u6D4B\u8BD5\u8FD9\u4E2A\u8F93\u5165\u9879\uFF0C\u663E\u7136\u4E0D\u53EF\u80FD\u7528 0~100 \u7684\u6BCF\u4E00\u4E2A\u6570\u53BB\u6D4B\u8BD5\u3002\u901A\u8FC7\u9700\u6C42\u63CF\u8FF0\u53EF\u4EE5\u77E5\u9053\uFF0C\u8F93\u5165 0~59 \u4E4B\u95F4\u7684\u4EFB\u610F\u6574\u6570\uFF0C\u4EE5\u53CA\u8F93\u5165 60~100 \u4E4B\u95F4\u7684\u4EFB\u610F\u6574\u6570\uFF0C\u53BB\u9A8C\u8BC1\u548C\u63ED\u9732\u8F93\u5165\u6846\u7684\u6F5C\u5728\u7F3A\u9677\u53EF\u4EE5\u770B\u505A\u662F\u7B49\u4EF7\u7684\u3002</p><p>\u90A3\u4E48\u8FD9\u5C31\u53EF\u4EE5\u5728 0~59 \u548C 60~100 \u4E4B\u95F4\u5404\u968F\u673A\u62BD\u53D6\u4E00\u4E2A\u6574\u6570\u6765\u8FDB\u884C\u9A8C\u8BC1\u3002\u8FD9\u6837\u7684\u8BBE\u8BA1\u5C31\u6784\u6210\u4E86\u6240\u8C13\u7684\u201C\u6709\u6548\u7B49\u4EF7\u7C7B\u201D\u3002</p><p>\u4F60\u4E0D\u8981\u89C9\u5F97\u8FDB\u884C\u5230\u8FD9\u91CC\uFF0C\u5DF2\u7ECF\u5B8C\u6210\u4E86\u7B49\u4EF7\u7C7B\u5212\u5206\u7684\u5DE5\u4F5C\uFF0C\u56E0\u4E3A<strong>\u7B49\u4EF7\u7C7B\u5212\u5206\u65B9\u6CD5\u7684\u53E6\u4E00\u4E2A\u5173\u952E\u70B9\u662F\u8981\u627E\u51FA\u6240\u6709\u201C\u65E0\u6548\u7B49\u4EF7\u7C7B\u201D</strong>\u3002\u663E\u7136\uFF0C\u5982\u679C\u8F93\u5165\u7684\u6210\u7EE9\u662F\u8D1F\u6570\uFF0C\u6216\u8005\u662F\u5927\u4E8E 100 \u7684\u6570\u7B49\u90FD\u6784\u6210\u4E86\u201C\u65E0\u6548\u7B49\u4EF7\u7C7B\u201D\u3002</p><p>\u5728\u8003\u8651\u4E86\u65E0\u6548\u7B49\u4EF7\u7C7B\u540E\uFF0C\u6700\u7EC8\u8BBE\u8BA1\u7684\u6D4B\u8BD5\u7528\u4F8B\u4E3A\uFF1A</p><p>\u6709\u6548\u7B49\u4EF7\u7C7B 1\uFF1A0~59 \u4E4B\u95F4\u7684\u4EFB\u610F\u6574\u6570\uFF1B \u6709\u6548\u7B49\u4EF7\u7C7B 2\uFF1A59~100 \u4E4B\u95F4\u7684\u4EFB\u610F\u6574\u6570\uFF1B \u65E0\u6548\u7B49\u4EF7\u7C7B 1\uFF1A\u5C0F\u4E8E 0 \u7684\u8D1F\u6570\uFF1B \u65E0\u6548\u7B49\u4EF7\u7C7B 2\uFF1A\u5927\u4E8E 100 \u7684\u6574\u6570\uFF1B \u65E0\u6548\u7B49\u4EF7\u7C7B 3\uFF1A0~100 \u4E4B\u95F4\u7684\u4EFB\u4F55\u6D6E\u70B9\u6570\uFF1B \u65E0\u6548\u7B49\u4EF7\u7C7B 4\uFF1A\u5176\u4ED6\u4EFB\u610F\u975E\u6570\u5B57\u5B57\u7B26\u3002</p><p><strong>\u7B2C\u4E8C\uFF0C\u8FB9\u754C\u503C\u5206\u6790\u65B9\u6CD5</strong></p><p>\u8FB9\u754C\u503C\u5206\u6790\u662F\u5BF9\u7B49\u4EF7\u7C7B\u5212\u5206\u7684\u8865\u5145\uFF0C\u4F60\u4ECE\u5DE5\u7A0B\u5B9E\u8DF5\u7ECF\u9A8C\u4E2D\u53EF\u4EE5\u53D1\u73B0\uFF0C\u5927\u91CF\u7684\u9519\u8BEF\u53D1\u751F\u5728\u8F93\u5165\u8F93\u51FA\u7684\u8FB9\u754C\u503C\u4E0A\uFF0C\u6240\u4EE5\u9700\u8981\u5BF9\u8FB9\u754C\u503C\u8FDB\u884C\u91CD\u70B9\u6D4B\u8BD5\uFF0C\u901A\u5E38\u9009\u53D6\u6B63\u597D\u7B49\u4E8E\u3001\u521A\u521A\u5927\u4E8E\u6216\u521A\u521A\u5C0F\u4E8E\u8FB9\u754C\u7684\u503C\u4F5C\u4E3A\u6D4B\u8BD5\u6570\u636E\u3002</p><p>\u6211\u4EEC\u7EE7\u7EED\u770B\u5B66\u751F\u4FE1\u606F\u7CFB\u7EDF\u4E2D\u201C\u8003\u8BD5\u6210\u7EE9\u201D\u7684\u4F8B\u5B50\uFF0C\u9009\u53D6\u7684\u8FB9\u754C\u503C\u6570\u636E\u5E94\u8BE5\u5305\u62EC\uFF1A-1\uFF0C0\uFF0C1\uFF0C59\uFF0C60\uFF0C61\uFF0C99\uFF0C100\uFF0C101\u3002</p><p><strong>\u7B2C\u4E09\uFF0C\u9519\u8BEF\u63A8\u6D4B\u65B9\u6CD5</strong></p><p>\u9519\u8BEF\u63A8\u6D4B\u65B9\u6CD5\u662F\u6307\u57FA\u4E8E\u5BF9\u88AB\u6D4B\u8BD5\u8F6F\u4EF6\u7CFB\u7EDF\u8BBE\u8BA1\u7684\u7406\u89E3\u3001\u8FC7\u5F80\u7ECF\u9A8C\u4EE5\u53CA\u4E2A\u4EBA\u76F4\u89C9\uFF0C\u63A8\u6D4B\u51FA\u8F6F\u4EF6\u53EF\u80FD\u5B58\u5728\u7684\u7F3A\u9677\uFF0C\u4ECE\u800C\u6709\u9488\u5BF9\u6027\u5730\u8BBE\u8BA1\u6D4B\u8BD5\u7528\u4F8B\u7684\u65B9\u6CD5\u3002\u8FD9\u4E2A\u65B9\u6CD5\u5F3A\u8C03\u7684\u662F\u5BF9\u88AB\u6D4B\u8BD5\u8F6F\u4EF6\u7684\u9700\u6C42\u7406\u89E3\u4EE5\u53CA\u8BBE\u8BA1\u5B9E\u73B0\u7684\u7EC6\u8282\u628A\u63E1\uFF0C\u5F53\u7136\u8FD8\u6709\u4E2A\u4EBA\u7684\u80FD\u529B\u3002</p><p>\u9519\u8BEF\u63A8\u6D4B\u6CD5\u548C\u76EE\u524D\u975E\u5E38\u6D41\u884C\u7684\u201C\u63A2\u7D22\u5F0F\u6D4B\u8BD5\u65B9\u6CD5\u201D\u7684\u57FA\u672C\u601D\u60F3\u548C\u7406\u5FF5\u662F\u4E0D\u8C0B\u800C\u5408\u7684\uFF0C\u8FD9\u7C7B\u65B9\u6CD5\u5728\u76EE\u524D\u7684\u654F\u6377\u5F00\u53D1\u6A21\u5F0F\u4E0B\u7684\u6295\u5165\u4EA7\u51FA\u6BD4\u5F88\u9AD8\uFF0C\u56E0\u6B64\u88AB\u5E7F\u6CDB\u5E94\u7528\u3002\u4F46\u662F\uFF0C\u8FD9\u4E2A\u65B9\u6CD5\u7684\u7F3A\u70B9\u4E5F\u663E\u800C\u6613\u89C1\uFF0C\u90A3\u5C31\u662F\u96BE\u4EE5\u7CFB\u7EDF\u5316\uFF0C\u5E76\u4E14\u8FC7\u5EA6\u4F9D\u8D56\u4E2A\u4EBA\u80FD\u529B\u3002</p><p>\u6BD4\u5982\uFF0CWeb \u754C\u9762\u7684 GUI \u529F\u80FD\u6D4B\u8BD5\uFF0C\u9700\u8981\u8003\u8651\u6D4F\u89C8\u5668\u5728\u6709\u7F13\u5B58\u548C\u6CA1\u6709\u7F13\u5B58\u4E0B\u7684\u8868\u73B0\uFF1BWeb Service \u7684 API \u6D4B\u8BD5\uFF0C\u9700\u8981\u8003\u8651\u88AB\u6D4B API \u6240\u4F9D\u8D56\u7684\u7B2C\u4E09\u65B9 API \u51FA\u9519\u4E0B\u7684\u5904\u7406\u903B\u8F91\uFF1B\u5BF9\u4E8E\u4EE3\u7801\u7EA7\u7684\u5355\u5143\u6D4B\u8BD5\uFF0C\u9700\u8981\u8003\u8651\u88AB\u6D4B\u51FD\u6570\u7684\u8F93\u5165\u53C2\u6570\u4E3A\u7A7A\u60C5\u51B5\u4E0B\u7684\u5185\u90E8\u5904\u7406\u903B\u8F91\u7B49\u7B49\u3002\u7531\u6B64\u53EF\u89C1\uFF0C\u8FD9\u4E9B\u6D4B\u8BD5\u7528\u4F8B\u7684\u8BBE\u8BA1\u90FD\u662F\u57FA\u4E8E\u66FE\u7ECF\u9047\u5230\u7684\u95EE\u9898\u800C\u8FDB\u884C\u7684\u9519\u8BEF\u63A8\u6D4B\uFF0C\u5F88\u5927\u7A0B\u5EA6\u4E0A\u53D6\u51B3\u4E8E\u4E2A\u4EBA\u80FD\u529B\u3002</p><p>\u5728\u8F6F\u4EF6\u4F01\u4E1A\u7684\u5177\u4F53\u5B9E\u8DF5\u4E2D\uFF0C\u4E3A\u4E86\u964D\u4F4E\u5BF9\u4E2A\u4EBA\u80FD\u529B\u7684\u4F9D\u8D56\uFF0C\u901A\u5E38\u4F1A\u5EFA\u7ACB\u5E38\u89C1\u7F3A\u9677\u77E5\u8BC6\u5E93\uFF0C\u5728\u6D4B\u8BD5\u8BBE\u8BA1\u7684\u8FC7\u7A0B\u4E2D\uFF0C\u4F1A\u4F7F\u7528\u7F3A\u9677\u77E5\u8BC6\u5E93\u4F5C\u4E3A\u68C0\u67E5\u70B9\u5217\u8868\uFF08checklist\uFF09\uFF0C\u53BB\u5E2E\u52A9\u4F18\u5316\u8865\u5145\u6D4B\u8BD5\u7528\u4F8B\u7684\u8BBE\u8BA1\u3002</p><p>\u5BF9\u4E8E\u4E2D\u5C0F\u4F01\u4E1A\uFF0C\u53EF\u80FD\u6700\u521D\u7684\u65B9\u6CD5\u5C31\u662F\u5EFA\u7ACB\u4E00\u4E2A\u7B80\u5355\u7684 wiki \u9875\u9762\uFF0C\u8BA9\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u5B8C\u6210\u6D4B\u8BD5\u7528\u4F8B\u7684\u6700\u521D\u8BBE\u8BA1\u540E\u5BF9\u5E94\u8FD9\u4E2A wiki \u9875\u9762\u5148\u505A\u4E00\u8F6E\u81EA\u68C0\uFF0C\u5982\u679C\u5728\u540E\u7EED\u6D4B\u8BD5\u4E2D\u53D1\u73B0\u4E86\u65B0\u7684\u70B9\uFF0C\u5C31\u4F1A\u7EE7\u7EED\u5B8C\u5584\u8FD9\u4E2A wiki \u9875\u9762\u3002</p><p>\u5BF9\u4E8E\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\u6BD4\u8F83\u6210\u719F\u7684\u4E2D\u5927\u578B\u8F6F\u4EF6\u4F01\u4E1A\uFF0C\u901A\u5E38\u4F1A\u4EE5\u8BE5\u7F3A\u9677\u77E5\u8BC6\u5E93\u4F5C\u4E3A\u6570\u636E\u9A71\u52A8\u6D4B\u8BD5\u7684\u8F93\u5165\u6765\u81EA\u52A8\u751F\u6210\u90E8\u5206\u7684\u6D4B\u8BD5\u6570\u636E\uFF0C\u8FD9\u90E8\u5206\u5185\u5BB9\u6211\u4F1A\u5728\u540E\u9762\u7684\u6587\u7AE0\u4E2D\u8BE6\u7EC6\u4ECB\u7ECD\u3002</p><p><strong>\u5982\u4F55\u624D\u80FD\u8BBE\u8BA1\u51FA\u201C\u597D\u7684\u201D\u6D4B\u8BD5\u7528\u4F8B\uFF1F</strong></p><p>\u638C\u63E1\u4E86\u6700\u57FA\u672C\u7684\u4E09\u79CD\u8BBE\u8BA1\u6D4B\u8BD5\u7528\u4F8B\u7684\u65B9\u6CD5\uFF0C\u4F60\u5C31\u76F8\u5F53\u4E8E\u62FF\u5230\u4E86\u6253\u4ED7\u6240\u9700\u8981\u7684\u67AA\u652F\u5F39\u836F\uFF0C\u63A5\u4E0B\u6765\u5C31\u662F\u5982\u4F55\u5728\u5B9E\u6218\u4E2D\u7528\u8FD9\u4E9B\u6B66\u5668\u6253\u4E2A\u5927\u80DC\u4ED7\u4E86\u3002</p><p><strong>\u5728\u771F\u5B9E\u7684\u5DE5\u7A0B\u5B9E\u8DF5\u4E2D\uFF0C\u4E0D\u540C\u7684\u8F6F\u4EF6\u9879\u76EE\u5728\u7814\u53D1\u751F\u547D\u5468\u671F\u7684\u5404\u4E2A\u9636\u6BB5\u90FD\u4F1A\u6709\u4E0D\u540C\u7684\u6D4B\u8BD5\u7C7B\u578B</strong>\u3002 \u6BD4\u5982\uFF0C\u4F20\u7EDF\u8F6F\u4EF6\u7684\u5F00\u53D1\u9636\u6BB5\u901A\u5E38\u4F1A\u6709\u5355\u5143\u6D4B\u8BD5\uFF0C\u8F6F\u4EF6\u6A21\u5757\u96C6\u6210\u9636\u6BB5\u4F1A\u6709\u4EE3\u7801\u7EA7\u96C6\u6210\u6D4B\u8BD5\uFF0C\u6253\u5305\u90E8\u7F72\u540E\u4F1A\u6709\u9762\u5411\u7EC8\u7AEF\u7528\u6237\u7684 GUI \u6D4B\u8BD5\uFF1B\u518D\u6BD4\u5982\uFF0C\u7535\u5546\u7F51\u7AD9\u7684\u6D4B\u8BD5\u4F1A\u5206\u4E3A\u670D\u52A1\u5668\u7AEF\u57FA\u4E8E API \u7684\u6D4B\u8BD5\u3001\u4E2D\u95F4\u4EF6\u6D4B\u8BD5\u3001\u524D\u7AEF GUI \u6D4B\u8BD5\u7B49\u3002</p><p><strong>\u5BF9\u4E8E\u6BCF\u4E00\u79CD\u4E0D\u540C\u7684\u6D4B\u8BD5\u7C7B\u578B\uFF0C\u8BBE\u8BA1\u51FA\u201C\u597D\u7684\u201D\u6D4B\u8BD5\u7528\u4F8B\u7684\u5173\u6CE8\u70B9\u548C\u65B9\u6CD5\u8BBA\u53EF\u80FD\u4F1A\u6709\u5F88\u5927\u7684\u5DEE\u5F02</strong>\uFF0C \u6709\u4E9B\u53EF\u80FD\u91C7\u7528\u9ED1\u76D2\u65B9\u6CD5\uFF0C\u6709\u4E9B\u53EF\u80FD\u91C7\u7528\u767D\u76D2\u65B9\u6CD5\uFF0C\u6709\u4E9B\u8FD8\u4F1A\u91C7\u7528\u7070\u76D2\u65B9\u6CD5\uFF08\u6BD4\u5982\uFF0C\u5FAE\u670D\u52A1\u67B6\u6784\u4E2D\u7684\u6D4B\u8BD5\uFF09\uFF0C\u6240\u4EE5\u5F88\u96BE\u6709\u4E00\u5957\u653E\u4E4B\u56DB\u6D77\u800C\u7686\u51C6\u7684\u5957\u8DEF\u3002</p><p>\u6240\u4EE5\uFF0C\u5728\u8FD9\u7BC7\u6587\u7AE0\u4E2D\uFF0C\u6211\u4EC5\u4EE5\u6700\u5E38\u89C1\u3001\u6700\u5BB9\u6613\u7406\u89E3\u7684\u9762\u5411\u7EC8\u7AEF\u7528\u6237\u7684 GUI \u6D4B\u8BD5\u4E3A\u4F8B\uFF0C\u8DDF\u4F60\u804A\u804A\u5982\u4F55\u624D\u80FD\u8BBE\u8BA1\u4E00\u4E2A\u201C\u597D\u7684\u201D\u6D4B\u8BD5\u7528\u4F8B\u3002</p><p>\u9762\u5411\u7EC8\u7AEF\u7528\u6237\u7684 GUI \u6D4B\u8BD5\uFF0C\u6700\u6838\u5FC3\u7684\u6D4B\u8BD5\u70B9\u5C31\u662F\u9A8C\u8BC1\u8F6F\u4EF6\u5BF9\u9700\u6C42\u7684\u6EE1\u8DB3\u7A0B\u5EA6\uFF0C\u8FD9\u5C31\u8981\u6C42\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u5BF9\u88AB\u6D4B\u8F6F\u4EF6\u7684\u9700\u6C42\u6709\u6DF1\u5165\u7684\u7406\u89E3\u3002\u5728\u6211\u770B\u6765\uFF0C\u6DF1\u5165\u7406\u89E3\u88AB\u6D4B\u8F6F\u4EF6\u9700\u6C42\u7684\u6700\u597D\u65B9\u6CD5\u662F\uFF0C\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u5728\u9700\u6C42\u5206\u6790\u548C\u8BBE\u8BA1\u9636\u6BB5\u5C31\u5F00\u59CB\u4ECB\u5165\uFF0C\u56E0\u4E3A\u8FD9\u4E2A\u9636\u6BB5\u662F\u7406\u89E3\u548C\u638C\u63E1\u8F6F\u4EF6\u7684\u539F\u59CB\u4E1A\u52A1\u9700\u6C42\u7684\u6700\u597D\u65F6\u673A\u3002</p><p>\u53EA\u6709\u771F\u6B63\u7406\u89E3\u4E86\u539F\u59CB\u4E1A\u52A1\u9700\u6C42\u4E4B\u540E\uFF0C\u624D\u6709\u53EF\u80FD\u4ECE\u4E1A\u52A1\u9700\u6C42\u7684\u89D2\u5EA6\u53BB\u8BBE\u8BA1\u9488\u5BF9\u6027\u660E\u786E\u3001\u4ECE\u7EC8\u7AEF\u7528\u6237\u4F7F\u7528\u573A\u666F\u8003\u8651\u7684\u7AEF\u5230\u7AEF\uFF08End-2-End\uFF09\u7684\u6D4B\u8BD5\u7528\u4F8B\u96C6\u3002\u8FD9\u4E2A\u9636\u6BB5\u7684\u6D4B\u8BD5\u7528\u4F8B\u8BBE\u8BA1\uFF0C\u4E3B\u8981\u76EE\u7684\u662F\u9A8C\u8BC1\u5404\u4E2A\u4E1A\u52A1\u9700\u6C42\u662F\u5426\u88AB\u6EE1\u8DB3\uFF0C\u4E3B\u8981\u91C7\u7528\u57FA\u4E8E\u9ED1\u76D2\u7684\u6D4B\u8BD5\u8BBE\u8BA1\u65B9\u6CD5\u3002</p><p><em>\u5728\u5177\u4F53\u7684\u7528\u4F8B\u8BBE\u8BA1\u65F6\uFF0C\u9996\u5148\u9700\u8981\u641E\u6E05\u695A\u6BCF\u4E00\u4E2A\u4E1A\u52A1\u9700\u6C42\u6240\u5BF9\u5E94\u7684\u591A\u4E2A\u8F6F\u4EF6\u529F\u80FD\u9700\u6C42\u70B9\uFF0C\u7136\u540E\u5206\u6790\u51FA\u6BCF\u4E2A\u8F6F\u4EF6\u529F\u80FD\u9700\u6C42\u70B9\u5BF9\u5E94\u7684\u591A\u4E2A\u6D4B\u8BD5\u9700\u6C42\u70B9\uFF0C\u6700\u540E\u518D\u9488\u5BF9\u6BCF\u4E2A\u6D4B\u8BD5\u9700\u6C42\u70B9\u8BBE\u8BA1\u6D4B\u8BD5\u7528\u4F8B</em>\u3002</p><p>\u8FD9\u4E2A\u7528\u4F8B\u8BBE\u8BA1\u8FC7\u7A0B\uFF0C\u4F60\u53EF\u80FD\u89C9\u5F97\u6709\u70B9\u7ED5\uFF0C\u4F46\u662F\u6CA1\u5173\u7CFB\uFF0C\u6211\u4EE5\u201C\u7528\u6237\u767B\u5F55\u201D\u529F\u80FD\u7684\u6D4B\u8BD5\u7528\u4F8B\u8BBE\u8BA1\u4E3A\u4F8B\uFF0C\u753B\u4E86\u4E00\u5F20\u56FE\u6765\u5E2E\u4F60\u7406\u6E05\u8FD9\u4E9B\u6982\u5FF5\u4E4B\u95F4\u7684\u6620\u5C04\u5173\u7CFB\u3002</p><p>\u56FE\u4E2D\u7684\u4E1A\u52A1\u9700\u6C42\u5230\u8F6F\u4EF6\u529F\u80FD\u9700\u6C42\u3001\u8F6F\u4EF6\u529F\u80FD\u9700\u6C42\u5230\u6D4B\u8BD5\u9700\u6C42\uFF0C\u4EE5\u53CA\u6D4B\u8BD5\u9700\u6C42\u5230\u6D4B\u8BD5\u7528\u4F8B\u7684\u6620\u5C04\u5173\u7CFB\uFF0C\u5728\u975E\u4E92\u8054\u7F51\u8F6F\u4EF6\u4F01\u4E1A\u7684\u5B9E\u8DF5\u4E2D\uFF0C\u901A\u5E38\u4F1A\u4F7F\u7528\u9700\u6C42\u8FFD\u8E2A\u7BA1\u7406\u5DE5\u5177\uFF08\u6BD4\u5982 ALM\u3001DOORS\u3001JIRA\u3001TestLink \u7B49\uFF09\u6765\u7BA1\u7406\uFF0C\u5E76\u4EE5\u6B64\u6765\u8861\u91CF\u6D4B\u8BD5\u7528\u4F8B\u5BF9\u4E1A\u52A1\u9700\u6C42\u3001\u8F6F\u4EF6\u529F\u80FD\u9700\u6C42\u7684\u8986\u76D6\u7387\u3002 <img src="https://static001.geekbang.org/resource/image/f1/f7/f1adcc92da9091037ccc022f29911ef7.png" alt=""> \u5177\u4F53\u5230\u6D4B\u8BD5\u7528\u4F8B\u672C\u8EAB\u7684\u8BBE\u8BA1\uFF0C\u6709\u4E24\u4E2A\u5173\u952E\u70B9\u9700\u8981\u4F60\u6CE8\u610F\u3002</p><ol><li><p><strong>\u4ECE\u8F6F\u4EF6\u529F\u80FD\u9700\u6C42\u51FA\u53D1\uFF0C\u5168\u9762\u5730\u3001\u65E0\u9057\u6F0F\u5730\u8BC6\u522B\u51FA\u6D4B\u8BD5\u9700\u6C42\u662F\u81F3\u5173\u91CD\u8981\u7684\uFF0C\u8FD9\u5C06\u76F4\u63A5\u5173\u7CFB\u5230\u7528\u4F8B\u7684\u6D4B\u8BD5\u8986\u76D6\u7387</strong>\u3002 \u6BD4\u5982\uFF0C\u5982\u679C\u4F60\u6CA1\u6709\u8BC6\u522B\u51FA\u7528\u6237\u767B\u5F55\u529F\u80FD\u7684\u5B89\u5168\u6027\u6D4B\u8BD5\u9700\u6C42\uFF0C\u90A3\u4E48\u540E\u7EED\u8BBE\u8BA1\u7684\u6D4B\u8BD5\u7528\u4F8B\u5C31\u5B8C\u5168\u4E0D\u4F1A\u6D89\u53CA\u5B89\u5168\u6027\uFF0C\u6700\u7EC8\u9020\u6210\u91CD\u8981\u6D4B\u8BD5\u6F0F\u6D1E\u3002</p></li><li><p><strong>\u5BF9\u4E8E\u8BC6\u522B\u51FA\u7684\u6BCF\u4E2A\u6D4B\u8BD5\u9700\u6C42\u70B9\uFF0C\u9700\u8981\u7EFC\u5408\u8FD0\u7528\u7B49\u4EF7\u7C7B\u5212\u5206\u3001\u8FB9\u754C\u503C\u5206\u6790\u548C\u9519\u8BEF\u63A8\u6D4B\u65B9\u6CD5\u6765\u5168\u9762\u5730\u8BBE\u8BA1\u6D4B\u8BD5\u7528\u4F8B</strong>\u3002 \u8FD9\u91CC\u9700\u8981\u6CE8\u610F\u7684\u662F\uFF0C\u8981\u7EFC\u5408\u8FD0\u7528\u8FD9\u4E09\u79CD\u65B9\u6CD5\uFF0C\u5E76\u9488\u5BF9\u6BCF\u4E2A\u6D4B\u8BD5\u9700\u6C42\u70B9\u7684\u5177\u4F53\u60C5\u51B5\uFF0C\u8FDB\u884C\u7075\u6D3B\u9009\u62E9\u3002 \u4EE5\u201C\u7528\u6237\u767B\u5F55\u201D\u7684\u529F\u80FD\u6027\u6D4B\u8BD5\u9700\u6C42\u4E3A\u4F8B\uFF0C\u4F60\u9996\u5148\u5E94\u8BE5\u5BF9\u201C\u7528\u6237\u540D\u201D\u548C\u201C\u5BC6\u7801\u201D\u8FD9\u4E24\u4E2A\u8F93\u5165\u9879\u5206\u522B\u8FDB\u884C\u7B49\u4EF7\u7C7B\u5212\u5206\uFF0C\u5217\u51FA\u5BF9\u5E94\u7684\u6709\u6548\u7B49\u4EF7\u7C7B\u548C\u65E0\u6548\u7B49\u4EF7\u7C7B\uFF0C\u5BF9\u4E8E\u65E0\u6548\u7B49\u4EF7\u7C7B\u7684\u8BC6\u522B\u53EF\u4EE5\u91C7\u7528\u9519\u8BEF\u731C\u6D4B\u6CD5\uFF08\u6BD4\u5982\uFF0C\u7528\u6237\u540D\u5305\u542B\u7279\u6B8A\u5B57\u7B26\u7B49\uFF09\uFF0C\u7136\u540E\u57FA\u4E8E\u4E24\u8005\u53EF\u80FD\u7684\u7EC4\u5408\uFF0C\u8BBE\u8BA1\u51FA\u7B2C\u4E00\u6279\u6D4B\u8BD5\u7528\u4F8B\u3002 \u7B49\u4EF7\u7C7B\u5212\u5206\u5B8C\u540E\uFF0C\u4F60\u9700\u8981\u8865\u5145\u201C\u7528\u6237\u540D\u201D\u548C\u201C\u5BC6\u7801\u201D\u8FD9\u4E24\u4E2A\u8F93\u5165\u9879\u7684\u8FB9\u754C\u503C\u7684\u6D4B\u8BD5\u7528\u4F8B\uFF0C\u6BD4\u5982\u7528\u6237\u540D\u4E3A\u7A7A\uFF08NULL\uFF09\u3001\u7528\u6237\u540D\u957F\u5EA6\u521A\u521A\u5927\u4E8E\u5141\u8BB8\u957F\u5EA6\u7B49\u3002</p></li></ol><p><strong>\u7528\u4F8B\u8BBE\u8BA1\u7684\u5176\u4ED6\u7ECF\u9A8C</strong></p><p>\u9664\u4E86\u4E0A\u9762\u4ECB\u7ECD\u7684\u65B9\u6CD5\u5916\uFF0C\u6211\u518D\u8DDF\u4F60\u5206\u4EAB\u4E09\u4E2A\u72EC\u5BB6\u201C\u79D8\u7C4D\u201D\uFF0C\u5E0C\u671B\u80FD\u591F\u5E2E\u4F60\u8BBE\u8BA1\u51FA\u201C\u597D\u7684\u201D\u6D4B\u8BD5\u7528\u4F8B\u96C6\u3002</p><ol><li><p><strong>\u53EA\u6709\u6DF1\u5165\u7406\u89E3\u88AB\u6D4B\u8BD5\u8F6F\u4EF6\u7684\u67B6\u6784\uFF0C\u4F60\u624D\u80FD\u8BBE\u8BA1\u51FA\u201C\u6709\u7684\u653E\u77E2\u201D\u7684\u6D4B\u8BD5\u7528\u4F8B\u96C6\uFF0C\u53BB\u53D1\u73B0\u7CFB\u7EDF\u8FB9\u754C\u4EE5\u53CA\u7CFB\u7EDF\u96C6\u6210\u4E0A\u7684\u6F5C\u5728\u7F3A\u9677\u3002</strong> \u4F5C\u4E3A\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\uFF0C\u5207\u5FCC\u4E0D\u80FD\u628A\u6574\u4E2A\u88AB\u6D4B\u7CFB\u7EDF\u770B\u4F5C\u4E00\u4E2A\u5927\u9ED1\u76D2\uFF0C\u4F60\u5FC5\u987B\u5BF9\u5185\u90E8\u7684\u67B6\u6784\u6709\u6E05\u695A\u7684\u8BA4\u8BC6\uFF0C\u6BD4\u5982\u6570\u636E\u5E93\u8FDE\u63A5\u65B9\u5F0F\u3001\u6570\u636E\u5E93\u7684\u8BFB\u5199\u5206\u79BB\u3001\u6D88\u606F\u4E2D\u95F4\u4EF6 Kafka \u7684\u914D\u7F6E\u3001\u7F13\u5B58\u7CFB\u7EDF\u7684\u5C42\u7EA7\u5206\u5E03\u3001\u7B2C\u4E09\u65B9\u7CFB\u7EDF\u7684\u96C6\u6210\u7B49\u7B49\u3002</p></li><li><p><strong>\u5FC5\u987B\u6DF1\u5165\u7406\u89E3\u88AB\u6D4B\u8F6F\u4EF6\u7684\u8BBE\u8BA1\u4E0E\u5B9E\u73B0\u7EC6\u8282\uFF0C\u6DF1\u5165\u7406\u89E3\u8F6F\u4EF6\u5185\u90E8\u7684\u5904\u7406\u903B\u8F91\u3002</strong> \u5355\u5355\u6839\u636E\u6D4B\u8BD5\u9700\u6C42\u70B9\u8BBE\u8BA1\u7684\u7528\u4F8B\uFF0C\u53EA\u80FD\u8986\u76D6\u201C\u8868\u9762\u201D\u7684\u4E00\u5C42\uFF0C\u5F80\u5F80\u4F1A\u8986\u76D6\u4E0D\u5230\u5185\u90E8\u7684\u5904\u7406\u6D41\u7A0B\u3001\u5206\u652F\u5904\u7406\uFF0C\u800C\u6CA1\u6709\u8986\u76D6\u5230\u7684\u90E8\u5206\u5C31\u5F88\u53EF\u80FD\u51FA\u73B0\u7F3A\u9677\u9057\u6F0F\u3002\u5728\u5177\u4F53\u5B9E\u8DF5\u4E2D\uFF0C\u4F60\u53EF\u4EE5\u901A\u8FC7\u4EE3\u7801\u8986\u76D6\u7387\u6307\u6807\u627E\u51FA\u53EF\u80FD\u7684\u6D4B\u8BD5\u9057\u6F0F\u70B9\u3002 \u540C\u65F6\uFF0C\u5207\u5FCC\u4E0D\u8981\u4EE5\u5F00\u53D1\u4EE3\u7801\u7684\u5B9E\u73B0\u4E3A\u4F9D\u636E\u8BBE\u8BA1\u6D4B\u8BD5\u7528\u4F8B\u3002\u56E0\u4E3A\u5F00\u53D1\u4EE3\u7801\u5B9E\u73B0\u7684\u9519\u8BEF\u4F1A\u5BFC\u81F4\u6D4B\u8BD5\u7528\u4F8B\u4E5F\u51FA\u9519\uFF0C\u6240\u4EE5\u4F60\u5E94\u8BE5\u6839\u636E\u539F\u59CB\u9700\u6C42\u8BBE\u8BA1\u6D4B\u8BD5\u7528\u4F8B\u3002</p></li><li><p><strong>\u9700\u8981\u5F15\u5165\u9700\u6C42\u8986\u76D6\u7387\u548C\u4EE3\u7801\u8986\u76D6\u7387\u6765\u8861\u91CF\u6D4B\u8BD5\u6267\u884C\u7684\u5B8C\u5907\u6027\uFF0C\u5E76\u4EE5\u6B64\u4E3A\u4F9D\u636E\u6765\u627E\u51FA\u9057\u6F0F\u7684\u6D4B\u8BD5\u70B9\u3002</strong> \u5173\u4E8E\u4EC0\u4E48\u662F\u9700\u6C42\u8986\u76D6\u7387\u548C\u4EE3\u7801\u8986\u76D6\u7387\uFF0C\u6211\u4F1A\u5728\u540E\u7EED\u7684\u6587\u7AE0\u4E2D\u8BE6\u7EC6\u4ECB\u7ECD\u3002</p></li></ol><p><strong>\u603B\u7ED3</strong></p><p>\u6700\u540E\uFF0C\u6211\u6765\u7B80\u5355\u603B\u7ED3\u4E00\u4E0B\u4ECA\u5929\u7684\u4E3B\u8981\u5185\u5BB9\u3002</p><p>\u9996\u5148\uFF0C\u4F60\u9700\u8981\u660E\u767D\uFF0C\u201C\u597D\u7684\u201D\u6D4B\u8BD5\u7528\u4F8B\u4E00\u5B9A\u662F\u4E00\u4E2A\u5B8C\u5907\u7684\u96C6\u5408\uFF0C\u5B83\u80FD\u591F\u8986\u76D6\u6240\u6709\u7B49\u4EF7\u7C7B\u4EE5\u53CA\u5404\u79CD\u8FB9\u754C\u503C\uFF0C\u800C\u80FD\u5426\u53D1\u73B0\u8F6F\u4EF6\u7F3A\u9677\u5E76\u4E0D\u662F\u8861\u91CF\u6D4B\u8BD5\u7528\u4F8B\u597D\u574F\u7684\u6807\u51C6\u3002</p><p>\u5176\u6B21\uFF0C\u8BBE\u8BA1\u6D4B\u8BD5\u7528\u4F8B\u7684\u65B9\u6CD5\u6709\u5F88\u591A\u79CD\uFF0C\u4F46\u7EFC\u5408\u8FD0\u7528\u7B49\u4EF7\u7C7B\u5212\u5206\u3001\u8FB9\u754C\u503C\u5206\u6790\u548C\u9519\u8BEF\u63A8\u6D4B\u65B9\u6CD5\uFF0C\u53EF\u4EE5\u6EE1\u8DB3\u7EDD\u5927\u591A\u6570\u8F6F\u4EF6\u6D4B\u8BD5\u7528\u4F8B\u8BBE\u8BA1\u7684\u9700\u6C42\u3002</p><p>\u518D\u6B21\uFF0C\u201C\u597D\u7684\u201D\u6D4B\u8BD5\u7528\u4F8B\u5728\u8BBE\u8BA1\u65F6\uFF0C\u9700\u8981\u4ECE\u8F6F\u4EF6\u529F\u80FD\u9700\u6C42\u51FA\u53D1\uFF0C\u5168\u9762\u5730\u3001\u65E0\u9057\u6F0F\u5730\u8BC6\u522B\u51FA\u6D4B\u8BD5\u9700\u6C42\u81F3\u5173\u91CD\u8981\u3002</p><p>\u6700\u540E\uFF0C\u5982\u679C\u60F3\u8BBE\u8BA1\u4E00\u4E2A\u201C\u597D\u7684\u201D\u6D4B\u8BD5\u7528\u4F8B\uFF0C\u4F60\u5FC5\u987B\u8981\u6DF1\u5165\u7406\u89E3\u88AB\u6D4B\u8F6F\u4EF6\u7684\u67B6\u6784\u8BBE\u8BA1\uFF0C\u6DF1\u5165\u8F6F\u4EF6\u5185\u90E8\u7684\u5904\u7406\u903B\u8F91\uFF0C\u9700\u6C42\u8986\u76D6\u7387\u548C\u4EE3\u7801\u8986\u76D6\u7387\u8FD9\u4E24\u4E2A\u6307\u6807\u53EF\u4EE5\u5E2E\u4F60\u8861\u91CF\u6D4B\u8BD5\u6267\u884C\u7684\u5B8C\u5907\u6027\u3002</p><p><strong>\u601D\u8003\u9898</strong></p><p>\u5728\u8BBE\u8BA1\u6D4B\u8BD5\u7528\u4F8B\u7684\u8FC7\u7A0B\u4E2D\uFF0C\u4F60\u6709\u54EA\u4E9B\u53EF\u4F9B\u5206\u4EAB\u7684\u597D\u7684\u5B9E\u8DF5\u548C\u65B9\u6CD5\uFF1F</p>',62);function s(n,g){return o}var e=p(r,[["render",s],["__file","02.html.vue"]]);export{e as default};
